<template>
  <div class="program-navbar">
    <div class="program-navbar-title">CHỦ ĐỀ & BÀI GIẢNG</div>
    <div class="program-navbar-content">
      <select
        class="program-navbar-selectchude"
        name="selectchude"
        @change="changeChude($event)"
        id="selectchude"
      >
        <option value="" disabled hidden :selected="currentChuDe == -1">
          Chọn chủ đề
        </option>
        <option
          v-for="chude in danhsachchude"
          v-bind:key="chude.id"
          v-bind:value="chude.id"
          :selected="chude.id == currentChuDe"
        >
          {{ chude.name }}
        </option>
      </select>
      <select
        class="program-navbar-selectbaihoc"
        name="selectbaihoc"
        @change="changeBaigiang($event)"
        id="selectbaihoc"
      >
        <option value="" disabled hidden :selected="currentBaiHoc == -1">
          Chọn bài học
        </option>
        <option
          v-for="baihoc in danhsachbaihoc"
          v-bind:key="baihoc.id"
          v-bind:value="baihoc.id"
          :selected="baihoc.id == currentBaiHoc"
        >
          {{ baihoc.name }}
        </option>
      </select>
    </div>
  </div>
</template>

<script>
import chudeData from "@/assets/data/chude.json";
import baihocData from "@/assets/data/baihoc.json";

const urlParams = new URLSearchParams(window.location.search);
// let idChuDe = urlParams.get("idChuDe");
// if (idChuDe == null) idChuDe = -1;

let idBaiHoc = urlParams.get("id");
if (idBaiHoc == null) idBaiHoc = -1;
let idChuDe = -1;
let baiHoc = baihocData.find((baihoc) => baihoc.id == idBaiHoc);
let dsbaihoc = [];
if (baiHoc != null) {
  idChuDe = baiHoc.idchude;
  let baihocOfChuDe = baihocData.reduce((filtered, baihoc) => {
    if (baihoc.idchude == idChuDe) {
      let filteredBaiHoc = Object.assign({}, baihoc);
      filtered.push(filteredBaiHoc);
    }
    return filtered;
  }, []);
  dsbaihoc = baihocOfChuDe;
}

export default {
  name: "ChuDeNavBar",
  methods: {
    changeChude(event) {
      console.log(event.target.value);
      let currentChuDe = { id: event.target.value };
      let baihocOfChuDe = baihocData.reduce((filtered, baihoc) => {
        if (baihoc.idchude == currentChuDe.id) {
          let filteredBaiHoc = Object.assign({}, baihoc);
          filtered.push(filteredBaiHoc);
        }
        return filtered;
      }, []);
      this.danhsachbaihoc = baihocOfChuDe;
      this.currentBaiHoc = -1;
    },
    changeBaigiang(event) {
      console.log(event.target.value);
      let idBaiHoc = event.target.value;
      window.location.href = `${window.location.protocol}//${window.location.host}/chi-tiet-bai-hoc.html?id=${idBaiHoc}`;
    },
    initData() {
      console.log(window.location.host);
    },
  },
  beforeMount() {
    this.initData();
  },
  data() {
    return {
      danhsachchude: chudeData,
      danhsachbaihoc: dsbaihoc,
      currentChuDe: idChuDe,
      currentBaiHoc: idBaiHoc,
    };
  },
};
</script>

